import 'dart:io';

import 'package:flutter_fractals/core/modules/nova_module.dart';
import 'package:flutter_test/flutter_test.dart';

import '../../support/shader_asset_expectations.dart';

void main() {
  const shaderRoot = 'shaders/escape_time_family/families/nova/';
  const parameterPlaneRoot = '${shaderRoot}parameter_plane/';
  const juliaSetsRoot = '${shaderRoot}julia_sets/';
  late final Set<String> declaredShaderAssets;

  setUpAll(() {
    declaredShaderAssets = loadDeclaredShaderAssets();
  });

  test('declared Nova shader assets exist on disk', () {
    final assets =
        declaredShaderAssetsStartingWith(declaredShaderAssets, shaderRoot);

    expect(assets, hasLength(9));
    expect(assets.where((asset) => asset.startsWith(parameterPlaneRoot)),
        hasLength(5));
    expect(assets.where((asset) => asset.startsWith(juliaSetsRoot)),
        hasLength(4));
    expect(
      assets.where((asset) => asset.substring(shaderRoot.length).contains('/')),
      hasLength(9),
      reason: 'Nova shaders belong in responsibility subfolders',
    );
    expectAssetsExist(assets);
  });

  test('catalog Nova shader assets are declared in pubspec', () {
    final catalogAssets = escapeTimeShaderAssetsStartingWith(shaderRoot);

    expect(catalogAssets, hasLength(9));
    expect(catalogAssets.where((asset) => asset.startsWith(parameterPlaneRoot)),
        hasLength(5));
    expect(catalogAssets.where((asset) => asset.startsWith(juliaSetsRoot)),
        hasLength(4));
    expectAssetsDeclaredAndExist(catalogAssets, declaredShaderAssets);
  });

  test('custom Nova module shader asset remains declared and loadable', () {
    final asset = buildNovaModule().shaderAsset;

    expect(asset, startsWith(parameterPlaneRoot));
    expect(declaredShaderAssets, contains(asset));
    expect(File(asset).existsSync(), isTrue, reason: '$asset should exist');
  });
}

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/modules/common_params.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/param_reader.dart';
import 'package:vector_math/vector_math.dart';

FractalModule buildNovaModule() {
  final parameters = [
    CommonFractalParams.iterations(defaultValue: 200),
    FractalParameter(
      id: 'relaxation',
      label: (l10n) => 'Relaxation',
      type: FractalParamType.float,
      min: 0.1,
      max: 3.0,
      step: 0.05,
      defaultValue: 1.0,
    ),
    CommonFractalParams.colorScheme64(defaultValue: 0),
  ];

  final defaultPreset = FractalPreset(
    id: 'nova-default',
    moduleId: 'nova',
    name: 'Default',
    params: {'iterations': 200, 'relaxation': 1.0, 'colorScheme': 2},
    view: FractalViewState(
        pan: Vector2(0.0, 0.0), zoom: 1.5, rotation: Vector3.zero()),
    createdAt: DateTime.now(),
    isBuiltIn: true,
  );

  return FractalModule(
    id: 'nova',
    displayName: (l10n) => 'Nova',
    dimension: FractalDimension.twoD,
    shaderAsset: 'shaders/escape_time_family/families/nova/parameter_plane/nova_gpu.frag',
    parameters: parameters,
    defaultPreset: defaultPreset,
    builtInPresets: [
      defaultPreset.copyWith(id: 'nova-classic', name: 'Classic'),
      defaultPreset.copyWith(
        id: 'nova-roots',
        name: 'Three Roots',
        params: {'iterations': 300, 'relaxation': 1.0, 'colorScheme': 1},
        view: FractalViewState(
            pan: Vector2(0.0, 0.0), zoom: 2.0, rotation: Vector3.zero()),
      ),
      defaultPreset.copyWith(
        id: 'nova-overrelaxed',
        name: 'Over-Relaxed',
        params: {'iterations': 250, 'relaxation': 1.5, 'colorScheme': 0},
        view: FractalViewState(
            pan: Vector2(0.0, 0.0), zoom: 1.5, rotation: Vector3.zero()),
      ),
    ],
    setUniforms: (shader, state, size, time) {
      shader.setFloat(0, time);
      shader.setFloat(1, size.width);
      shader.setFloat(2, size.height);
      shader.setFloat(3, state.view.pan.x);
      shader.setFloat(4, state.view.pan.y);
      shader.setFloat(5, state.view.zoom);
      shader.setFloat(6, readDouble(state.params, 'iterations', 200));
      shader.setFloat(7, readDouble(state.params, 'relaxation', 1.0));
      shader.setFloat(8, readDouble(state.params, 'colorScheme', 0));
      shader.setFloat(9, state.transparentBackground ? 1.0 : 0.0);
    },
  );
}

#include <flutter/runtime_effect.glsl>

precision highp float;

uniform float uTime;          // 0
uniform vec2  uResolution;    // 1-2
uniform vec2  uCenter;        // 3-4
uniform float uZoom;          // 5
uniform float uIterations;    // 6
uniform float uRelaxation;    // 7  (Newton relaxation coeff, default 1.0)
uniform float uColorScheme;   // 8
uniform float uTransparentBg; // 9

out vec4 fragColor;

// IEC 61966-2-1 sRGB transfer function (linear → display-encoded).
vec3 linearToSRGB(vec3 lin) {
  lin = clamp(lin, 0.0, 1.0);
  bvec3 cutoff = lessThan(lin, vec3(0.0031308));
  vec3 hi = 1.055 * pow(max(lin, vec3(0.0031308)), vec3(1.0 / 2.4)) - 0.055;
  vec3 lo = lin * 12.92;
  return mix(hi, lo, vec3(cutoff));
}

vec3 palette(float t, int scheme) {
  if (scheme == 0) {
    return vec3(0.5+0.5*cos(6.28318*(t+0.0)),0.5+0.5*cos(6.28318*(t+0.4)),0.5+0.5*cos(6.28318*(t+0.7)));
  } else if (scheme == 1) {
    return vec3(0.5+0.5*cos(6.28318*(t+0.5)),0.5+0.5*cos(6.28318*(t+0.3)),0.5+0.5*cos(6.28318*(t+0.0)));
  } else if (scheme == 2) {
    return vec3(0.5+0.5*cos(6.28318*(t+0.0)),0.5+0.5*cos(6.28318*(t+0.33)),0.5+0.5*cos(6.28318*(t+0.67)));
  } else if (scheme == 3) {
    float g = 0.5+0.5*cos(6.28318*t); return vec3(g);
  }

  float s = float(scheme);
  vec3 a = 0.55 + 0.15 * sin(vec3(1.0, 2.0, 3.0) * (0.37 * s + 0.1));
  vec3 b = 0.45 + 0.25 * cos(vec3(1.7, 2.3, 2.9) * (0.29 * s + 0.2));
  vec3 c = 1.0  + 0.80 * sin(vec3(0.8, 1.3, 1.7) * (0.11 * s + 0.3));
  vec3 d = fract(sin(vec3(12.9898, 78.233, 37.719) * (s + 0.5)) * 43758.5453);
  vec3 col = a + b * cos(6.28318 * (c * t + d));
  return clamp(col, 0.0, 1.0);
}


// Complex divide: (a+bi)/(c+di)
vec2 cdiv(vec2 a, vec2 b) {
  float d = dot(b, b);
  if (d < 1e-20) return vec2(1e10);
  return vec2(a.x*b.x + a.y*b.y, a.y*b.x - a.x*b.y) / d;
}

// Complex multiply
vec2 cmul(vec2 a, vec2 b) {
  return vec2(a.x*b.x - a.y*b.y, a.x*b.y + a.y*b.x);
}

// Complex square
vec2 csq(vec2 z) {
  return vec2(z.x*z.x - z.y*z.y, 2.0*z.x*z.y);
}

void main() {
  vec2 fragCoord = FlutterFragCoord().xy;
  float scale = min(uResolution.x, uResolution.y);
  vec2 uv = (fragCoord - 0.5*uResolution) / max(1.0, scale);
  vec2 c = uv / max(0.000001, uZoom) + uCenter;

  // Nova fractal: Newton's method on z^3 - 1 with additive c perturbation
  // z_{n+1} = z_n - R * f(z_n)/f'(z_n) + c
  // f(z) = z^3 - 1, f'(z) = 3z^2
  vec2 z = vec2(1.0, 0.0);  // start near root
  float R = uRelaxation;

  const int MAX_ITERS = 500;
  int target = int(clamp(uIterations, 0.0, float(MAX_ITERS)));
  int it = 0;
  float conv = 0.0;

  for (int j = 0; j < MAX_ITERS; j++) {
    if (j >= target) { it = target; break; }

    vec2 z2 = csq(z);
    vec2 z3 = cmul(z2, z);
    vec2 fz = z3 - vec2(1.0, 0.0);
    vec2 fpz = 3.0 * z2;
    vec2 step_val = cdiv(fz, fpz);
    z = z - R * step_val + c;

    float d = dot(step_val, step_val);
    if (d < 1e-10) { it = j; conv = d; break; }
    it = j + 1;
  }

  if (it >= target) {
    fragColor = (uTransparentBg > 0.5) ? vec4(0.0) : vec4(0.0,0.0,0.0,1.0);
    return;
  }

  // Color based on which root converged to + iteration count
  float angle = atan(z.y, z.x);
  float rootPhase = mod(angle / 6.28318 + 1.0, 1.0);
  float t = fract(float(it) / max(1.0, uIterations) + rootPhase * 0.33 + uTime*0.0001);
  vec3 color = palette(t, int(uColorScheme));
  fragColor = vec4(linearToSRGB(color), 1.0);
}

#include <flutter/runtime_effect.glsl>

precision highp float;

uniform float uTime;          // 0
uniform vec2  uResolution;    // 1-2
uniform vec2  uCenter;        // 3-4
uniform float uZoom;          // 5
uniform float uIterations;    // 6
uniform float uBailout;       // 7
uniform float uColorScheme;   // 8
uniform float uTransparentBg; // 9

out vec4 fragColor;

// IEC 61966-2-1 sRGB transfer function (linear → display-encoded).
vec3 linearToSRGB(vec3 lin) {
  lin = clamp(lin, 0.0, 1.0);
  bvec3 cutoff = lessThan(lin, vec3(0.0031308));
  vec3 hi = 1.055 * pow(max(lin, vec3(0.0031308)), vec3(1.0 / 2.4)) - 0.055;
  vec3 lo = lin * 12.92;
  return mix(hi, lo, vec3(cutoff));
}

vec3 iqPalette(float t, vec3 a, vec3 b, vec3 c, vec3 d) {
  return a + b * cos(6.28318530718 * (c * t + d));
}

vec3 palette(float t, int scheme) {
  if (scheme == 0) return clamp(iqPalette(t, vec3(0.50), vec3(0.50), vec3(1.0), vec3(0.00, 0.10, 0.20)), 0.0, 1.0);
  if (scheme == 1) return clamp(iqPalette(t, vec3(0.50), vec3(0.50), vec3(1.0), vec3(0.30, 0.20, 0.20)), 0.0, 1.0);
  if (scheme == 2) return clamp(iqPalette(t, vec3(0.55), vec3(0.45), vec3(1.0), vec3(0.10, 0.25, 0.35)), 0.0, 1.0);
  if (scheme == 3) {
    float g = 0.5 + 0.5 * cos(6.28318 * t);
    return vec3(g);
  }
  float s = float(scheme);
  vec3 d = fract(sin(vec3(12.9898, 78.233, 37.719) * (s + 0.37)) * 43758.5453);
  return clamp(iqPalette(t, vec3(0.52), vec3(0.48), vec3(1.0), d), 0.0, 1.0);
}

vec2 cmul(vec2 a, vec2 b) {
  return vec2(a.x * b.x - a.y * b.y, a.x * b.y + a.y * b.x);
}

vec2 cdivSafe(vec2 a, vec2 b) {
  float d = max(dot(b, b), 1e-20);
  return vec2(a.x * b.x + a.y * b.y, a.y * b.x - a.x * b.y) / d;
}

float rootDistanceSq(vec2 z, vec2 root) {
  vec2 d = z - root;
  return dot(d, d);
}

void main() {
  vec2 fragCoord = FlutterFragCoord().xy;
  float scale = min(uResolution.x, uResolution.y);
  vec2 uv = (fragCoord - 0.5 * uResolution) / max(1.0, scale);

  vec2 c = uv / max(0.000001, uZoom) + uCenter;
  vec2 z = c;
  float escapeSq = max(16.0, uBailout * uBailout);

  const int MAX_ITERS = 500;
  int target = int(clamp(uIterations, 0.0, float(MAX_ITERS)));
  int it = 0;

  for (int j = 0; j < MAX_ITERS; j++) {
    if (j >= target) { it = target; break; }

    vec2 z2 = cmul(z, z);
    vec2 z3 = cmul(z2, z);
    vec2 fz = z3 - vec2(1.0, 0.0);
    vec2 fpz = 3.0 * z2;
    vec2 step = cdivSafe(fz, fpz);

    z = z - step + c;

    if (dot(step, step) < 1e-13) { it = j; break; }
    if (dot(z, z) > escapeSq) { it = j; break; }
    it = j + 1;
  }

  if (it >= target) {
    fragColor = (uTransparentBg > 0.5) ? vec4(0.0) : vec4(0.0, 0.0, 0.0, 1.0);
    return;
  }

  vec2 r0 = vec2(1.0, 0.0);
  vec2 r1 = vec2(-0.5, 0.86602540378);
  vec2 r2 = vec2(-0.5, -0.86602540378);

  float d0 = rootDistanceSq(z, r0);
  float d1 = rootDistanceSq(z, r1);
  float d2 = rootDistanceSq(z, r2);

  float rootPhase = 0.0;
  if (d1 < d0 && d1 < d2) rootPhase = 0.3333333;
  else if (d2 < d0 && d2 < d1) rootPhase = 0.6666667;

  float t = fract(float(it) / max(1.0, uIterations) + rootPhase + uTime * 0.0001);
  fragColor = vec4(linearToSRGB(palette(t, int(uColorScheme))), 1.0);
}

#include <flutter/runtime_effect.glsl>

precision highp float;

// Nova Mandelbrot: z_{n+1} = z - (z^3 - 1)/(3z^2) + c
// Newton's method on z^3 - 1, perturbed by c.
// Convergent-style: color by which root the orbit approaches.
// Three roots of z^3 = 1: (1,0), (-0.5, sqrt(3)/2), (-0.5, -sqrt(3)/2)
uniform float uTime;          // 0
uniform vec2  uResolution;    // 1-2
uniform vec2  uCenter;        // 3-4
uniform float uZoom;          // 5
uniform float uIterations;    // 6
uniform float uBailout;       // 7
uniform float uColorScheme;   // 8
uniform float uTransparentBg; // 9

out vec4 fragColor;

vec3 linearToSRGB(vec3 lin) {
  lin = clamp(lin, 0.0, 1.0);
  bvec3 cutoff = lessThan(lin, vec3(0.0031308));
  vec3 hi = 1.055 * pow(max(lin, vec3(0.0031308)), vec3(1.0 / 2.4)) - 0.055;
  vec3 lo = lin * 12.92;
  return mix(hi, lo, vec3(cutoff));
}

vec3 palette(float t, int scheme) {
  if (scheme == 0) {
    return vec3(0.5 + 0.5 * cos(6.28318 * (t + 0.0)),
                0.5 + 0.5 * cos(6.28318 * (t + 0.4)),
                0.5 + 0.5 * cos(6.28318 * (t + 0.7)));
  } else if (scheme == 1) {
    return vec3(0.5 + 0.5 * cos(6.28318 * (t + 0.5)),
                0.5 + 0.5 * cos(6.28318 * (t + 0.3)),
                0.5 + 0.5 * cos(6.28318 * (t + 0.0)));
  } else if (scheme == 2) {
    return vec3(0.5 + 0.5 * cos(6.28318 * (t + 0.0)),
